"""
FISH launch inspector — extracts composable node specs from a launch file.

Runs BEFORE the real `ros2 launch`, walks the launch description in
"describe-only" mode (no service calls, no process spawns), and records
every ComposableNode and its target container to JSON.

Usage:
    python3 -m fish.launch_inspect <package> <launch_file> [arg1:=val1 ...]

Output (JSON on stdout):
    {
      "/container/full/ros/name": [
        {
          "package": "pointcloud_preprocessor",
          "plugin":  "pointcloud_preprocessor::CropBoxFilterComponent",
          "name":    "crop_box_filter_self",
          "namespace": "/sensing/lidar/top",
          "parameters": ["/opt/autoware/share/.../crop_box.param.yaml",
                         {"use_sim_time": true}],
          "remappings": [["input", "/sensing/lidar/top/pointcloud_raw"],
                         ["output", "/sensing/.../crop_box_filter_self/output"]]
        },
        ...
      ],
      ...
    }

Approach:
  1. Monkey-patch ComposableNode.__init__ and ComposableNodeContainer.__init__
     BEFORE importing anything from launch_ros that would instantiate them.
     Every instance created during launch description evaluation is captured.
  2. Use LaunchService + IncludeLaunchDescription to "visit" the launch
     without actually executing side-effect actions. Conditions and includes
     are resolved this way.
  3. Walk the captured instances, resolve substitutions using the same
     LaunchContext, and pair ComposableNodes with their containers.
  4. Emit JSON. On any error, emit an empty JSON object and exit 0 so
     the wrapper can continue without specs (graceful fallback).
"""

import json
import os
import sys
import traceback
from typing import Any, Optional


# Captured during launch description evaluation
_captured_containers: list = []   # ComposableNodeContainer instances
_captured_load_actions: list = [] # LoadComposableNodes instances
_captured_nodes: list = []        # ComposableNode instances (top-level, may be container-attached)
_captured_standalone_nodes: list = []  # Node (standalone executable) instances


def _patch_captures() -> None:
    """Install __init__ hooks on ComposableNode, ComposableNodeContainer,
    LoadComposableNodes, and Node so every instance is recorded."""
    from launch_ros.descriptions import ComposableNode
    from launch_ros.actions import ComposableNodeContainer, LoadComposableNodes, Node

    cn_orig = ComposableNode.__init__
    def cn_patched(self, *args, **kwargs):
        cn_orig(self, *args, **kwargs)
        # Materialize the remappings generator into a list so we can
        # iterate it multiple times during inspection.
        r = self._ComposableNode__remappings
        if r is not None and not isinstance(r, (list, tuple)):
            self._ComposableNode__remappings = list(r)
        _captured_nodes.append(self)
    ComposableNode.__init__ = cn_patched

    cnc_orig = ComposableNodeContainer.__init__
    def cnc_patched(self, *args, **kwargs):
        cnc_orig(self, *args, **kwargs)
        _captured_containers.append(self)
    ComposableNodeContainer.__init__ = cnc_patched

    lcn_orig = LoadComposableNodes.__init__
    def lcn_patched(self, *args, **kwargs):
        lcn_orig(self, *args, **kwargs)
        _captured_load_actions.append(self)
    LoadComposableNodes.__init__ = lcn_patched

    # Capture standalone Node instances (not containers — those inherit
    # from Node but are captured separately above).
    node_orig = Node.__init__
    def node_patched(self, *args, **kwargs):
        node_orig(self, *args, **kwargs)
        if not isinstance(self, ComposableNodeContainer):
            _captured_standalone_nodes.append(self)
    Node.__init__ = node_patched


def _resolve(value: Any, context) -> Any:
    """Resolve a launch Substitution (or list/tuple of them) to plain Python."""
    if value is None:
        return None
    if isinstance(value, (str, int, float, bool)):
        return value
    if isinstance(value, dict):
        return {_resolve(k, context): _resolve(v, context) for k, v in value.items()}
    if isinstance(value, (list, tuple)):
        # Could be a substitution list like [LaunchConfiguration("x"), "/foo"]
        from launch.utilities import perform_substitutions
        try:
            return perform_substitutions(context, list(value))
        except Exception:
            return [_resolve(v, context) for v in value]
    # Single Substitution-like
    if hasattr(value, "perform"):
        try:
            return value.perform(context)
        except Exception:
            return f"<unresolved:{type(value).__name__}>"
    return str(value)


def _find_launch_file(package: str, filename: str) -> Optional[str]:
    """Locate a launch file by walking the package share directory."""
    from ament_index_python.packages import get_package_share_directory
    try:
        share = get_package_share_directory(package)
    except Exception:
        return None
    for root, _, files in os.walk(share):
        if filename in files:
            return os.path.join(root, filename)
    return None


def _walk(entity, context, depth: int = 0, max_depth: int = 30) -> None:
    """Walk a launch entity tree WITHOUT triggering side effects.

    We only call .visit() on the small set of actions that expand the
    tree (IncludeLaunchDescription) or update the context with defaults
    (DeclareLaunchArgument). Other actions (ExecuteProcess, Node,
    ComposableNodeContainer, LoadComposableNodes) are skipped at visit
    time — the monkey-patched __init__ hooks already captured them when
    the launch description was constructed. For every entity we also
    descend into common child attributes so actions inside GroupAction,
    OpaqueFunction results etc. are reached.
    """
    if entity is None or depth > max_depth:
        return

    # Lazy imports
    from launch.actions import (
        DeclareLaunchArgument, IncludeLaunchDescription, GroupAction,
        OpaqueFunction, SetLaunchConfiguration,
    )
    from launch import LaunchDescription

    sub_entities = None
    try:
        if isinstance(entity, LaunchDescription):
            # LaunchDescription.entities is the public list
            sub_entities = list(entity.entities)
        elif isinstance(entity, IncludeLaunchDescription):
            # Safe to visit — loads the nested launch file
            sub_entities = entity.visit(context) or []
        elif isinstance(entity, (DeclareLaunchArgument, SetLaunchConfiguration)):
            # Safe to visit — sets launch configurations on context
            try:
                entity.visit(context)
            except Exception:
                pass
            sub_entities = []
        elif isinstance(entity, GroupAction):
            # Expand group into its children
            try:
                sub_entities = entity.get_sub_entities()
            except Exception:
                try:
                    sub_entities = entity.visit(context) or []
                except Exception:
                    sub_entities = []
        elif isinstance(entity, OpaqueFunction):
            # Executes a Python function that returns actions
            try:
                sub_entities = entity.visit(context) or []
            except Exception:
                sub_entities = []
        else:
            # Action with potential side effects — DO NOT visit.
            # Still try to get its static children for traversal.
            sub_entities = []
    except Exception:
        sub_entities = []

    if sub_entities:
        for sub in sub_entities:
            _walk(sub, context, depth + 1, max_depth)


def _container_name_for_node(
    node, containers_by_name: dict, load_targets_by_node_id: dict, context,
) -> Optional[str]:
    """Find which container a ComposableNode belongs to.

    Container ownership comes from two places:
      1. ComposableNodeContainer(composable_node_descriptions=[...])
         — containers own their nodes directly
      2. LoadComposableNodes(target_container=X, composable_node_descriptions=[...])
         — load action attaches nodes to a named target container
    """
    # Path 2: LoadComposableNodes by identity
    if id(node) in load_targets_by_node_id:
        return load_targets_by_node_id[id(node)]
    # Path 1: embedded in a container's descriptions
    for cname, container in containers_by_name.items():
        descs = getattr(container, "_ComposableNodeContainer__composable_node_descriptions", None) or []
        for d in descs:
            if d is node:
                return cname
    return None


def _full_container_name(container, context) -> str:
    """Get the full ROS name of a container: <namespace>/<name>."""
    name = _resolve(getattr(container, "_Node__node_name", None) or
                    getattr(container, "node_name", None), context)
    ns = _resolve(getattr(container, "_Node__node_namespace", None) or
                  getattr(container, "node_namespace", None), context)
    if name is None:
        return "<unknown>"
    if ns and ns != "/":
        return f"{ns.rstrip('/')}/{name}"
    return f"/{name}"


def _resolve_subs_list(subs_list, context) -> str:
    """Resolve a list (or tuple) of Substitutions to a single string."""
    from launch.utilities import perform_substitutions
    if subs_list is None:
        return ""
    if isinstance(subs_list, str):
        return subs_list
    if not isinstance(subs_list, (list, tuple)):
        subs_list = [subs_list]
    try:
        return perform_substitutions(context, list(subs_list))
    except Exception:
        # Fall back to per-element resolution
        parts = []
        for s in subs_list:
            if isinstance(s, str):
                parts.append(s)
            elif hasattr(s, "perform"):
                try:
                    parts.append(s.perform(context))
                except Exception:
                    parts.append("")
        return "".join(parts)


def _resolve_parameter_value(val, context):
    """Resolve a parameter VALUE side (not the key).

    Values can be primitives, ParameterValue objects, or substitution lists."""
    # Primitive — pass through
    if isinstance(val, (bool, int, float)):
        return val
    if isinstance(val, str):
        return val
    # ParameterValue has .evaluate(context)
    if hasattr(val, "evaluate"):
        try:
            return val.evaluate(context)
        except Exception:
            pass
    # Substitution list
    if isinstance(val, (list, tuple)):
        return _resolve_subs_list(val, context)
    if hasattr(val, "perform"):
        try:
            return val.perform(context)
        except Exception:
            return None
    return str(val)


def _resolve_parameters(params_tuple, context) -> list:
    """Resolve ComposableNode __parameters into plain-Python form.

    Structure of __parameters (per normalize_parameters):
      Tuple of items where each item is one of:
        - dict of {tuple-of-substitutions: primitive-or-ParameterValue}
            (from inline dict parameters= [{"key": value, ...}])
        - ParameterFile object (from a file path parameters= ["/path/to.yaml"])
        - substitution list of file path
    """
    if not params_tuple:
        return []

    out: list = []
    for item in params_tuple:
        # Case 1: ParameterFile object (wraps a YAML file path)
        if hasattr(item, "param_file"):
            try:
                # ParameterFile.param_file is a list of Substitutions
                path = _resolve_subs_list(item.param_file, context)
                if path:
                    out.append(path)
                continue
            except Exception:
                pass
        # Case 2: dict with substitution-tuple keys
        if isinstance(item, dict):
            d = {}
            for k, v in item.items():
                try:
                    key_str = _resolve_subs_list(k, context)
                    val = _resolve_parameter_value(v, context)
                    d[key_str] = val
                except Exception:
                    continue
            if d:
                out.append(d)
            continue
        # Case 3: substitution list / tuple (file path built from pieces)
        if isinstance(item, (list, tuple)):
            path = _resolve_subs_list(item, context)
            if path:
                out.append(path)
            continue
        # Case 4: plain string file path
        if isinstance(item, str):
            out.append(item)
            continue
        # Fallback: stringify
        out.append(str(item))
    return out


def _resolve_remappings(remaps, context) -> list:
    """Resolve a ComposableNode remappings list of (from_subs, to_subs) pairs.

    After normalize_remap_rules, each remap is a tuple of two substitution lists.
    """
    if not remaps:
        return []
    out = []
    for r in remaps:
        try:
            if isinstance(r, (list, tuple)) and len(r) == 2:
                src = _resolve_subs_list(r[0], context)
                dst = _resolve_subs_list(r[1], context)
                out.append([src, dst])
        except Exception:
            continue
    return out


