def _is_gpu_plugin(plugin: Any, package: Any) -> bool:
    """Heuristic: does this component's plugin/package suggest GPU use?"""
    haystack = ""
    if isinstance(plugin, str):
        haystack += plugin.lower()
    if isinstance(package, str):
        haystack += " " + package.lower()
    return any(kw in haystack for kw in GPU_PLUGIN_KEYWORDS)


def inspect_launch_description(ld, context) -> dict:
    """Inspect an already-loaded LaunchDescription.

    Shared core used by both `inspect_launch` (ros2 launch flow — finds the
    launch file under a package share dir) and `fish.launch_test_inspect`
    (launch_test flow — calls `generate_test_description()` on a test script
    and feeds the resulting LaunchDescription here).

    The caller is responsible for:
      - Calling `_patch_captures()` BEFORE creating the LaunchDescription.
      - Building the `context` (typically `LaunchService().context`).
      - Seeding launch configurations from CLI arguments.
    """
    # Walk the top-level description, letting conditions/includes expand.
    # This triggers nested generate_launch_description() calls which in turn
    # instantiate more ComposableNode / ComposableNodeContainer objects.
    _walk(ld, context)

    # Build container index by resolved full name
    containers_by_name: dict = {}
    for c in _captured_containers:
        try:
            full = _full_container_name(c, context)
            containers_by_name[full] = c
        except Exception:
            pass

    # Build "node → target container" map from LoadComposableNodes actions
    load_targets_by_node_id: dict = {}
    for lcn in _captured_load_actions:
        try:
            target = getattr(lcn, "_LoadComposableNodes__target_container", None)
            # target_container can be:
            #   - a string "/container_name"
            #   - a Substitution list like [TextSubstitution("/"), LaunchConfiguration("container")]
            #   - a ComposableNodeContainer object (reference to a defined container)
            from launch_ros.actions import ComposableNodeContainer
            if isinstance(target, ComposableNodeContainer):
                target_name = _full_container_name(target, context)
            else:
                target_name = _resolve(target, context)
            if not target_name or target_name.startswith("<unresolved"):
                continue
            # Ensure leading slash
            if not target_name.startswith("/"):
                target_name = "/" + target_name
            descs = getattr(lcn, "_LoadComposableNodes__composable_node_descriptions", None) or []
            for d in descs:
                load_targets_by_node_id[id(d)] = target_name
        except Exception:
            pass

    # Assemble the output
    result: dict = {}
    for node in _captured_nodes:
        try:
            cname = _container_name_for_node(
                node, containers_by_name, load_targets_by_node_id, context,
            )
            if not cname:
                continue
            spec = {
                "package": _resolve(
                    getattr(node, "_ComposableNode__package", None), context),
                "plugin": _resolve(
                    getattr(node, "_ComposableNode__node_plugin", None), context),
                "name": _resolve(
                    getattr(node, "_ComposableNode__node_name", None), context),
                "namespace": _resolve(
                    getattr(node, "_ComposableNode__node_namespace", None), context),
                "parameters": _resolve_parameters(
                    getattr(node, "_ComposableNode__parameters", None), context),
                "remappings": _resolve_remappings(
                    getattr(node, "_ComposableNode__remappings", None), context),
            }
            result.setdefault(cname, []).append(spec)
        except Exception:
            continue

    # Derive the set of GPU-hosting containers from plugin/package keywords.
    # Used by fish.launch_wrap to decide which containers to nsys-wrap.
    gpu_containers: list = []
    for cname, specs in result.items():
        if cname.startswith("__"):
            continue
        if any(
            _is_gpu_plugin(s.get("plugin"), s.get("package")) for s in specs
        ):
            gpu_containers.append(cname)
    result["__gpu_containers__"] = gpu_containers

    # Derive standalone GPU nodes from captured Node instances.
    # These are non-container executables that use GPU (e.g. shape_estimation).
    # Used by fish.launch_wrap to nsys-wrap them at launch time.
    gpu_nodes: list = []
    standalone_nodes: list = []
    for node in _captured_standalone_nodes:
        try:
            name = _resolve(
                getattr(node, "_Node__node_name", None), context)
            ns = _resolve(
                getattr(node, "_Node__node_namespace", None), context)
            executable = _resolve(
                getattr(node, "_Node__node_executable", None), context)
            package = _resolve(
                getattr(node, "_Node__package", None), context)

            full_name = f"{ns.rstrip('/')}/{name}" if ns and ns != "/" else f"/{name}" if name else None
            spec = {
                "name": name,
                "namespace": ns,
                "executable": executable,
                "package": package,
                "full_name": full_name,
            }
            standalone_nodes.append(spec)

            if _is_gpu_plugin(executable, package):
                gpu_nodes.append(full_name or name or executable)
        except Exception:
            continue

    result["__standalone_nodes__"] = standalone_nodes
    result["__gpu_nodes__"] = gpu_nodes

    return result


def inspect_launch(package: str, launch_file: str, launch_args: list) -> dict:
    """Inspect a `ros2 launch <package> <launch_file>` invocation.

    Locates the launch file under the package's share dir, loads it via
    AnyLaunchDescriptionSource, then delegates to `inspect_launch_description`.
    """
    _patch_captures()

    from launch import LaunchService
    from launch.launch_description_sources import AnyLaunchDescriptionSource

    launch_path = _find_launch_file(package, launch_file)
    if not launch_path:
        raise FileNotFoundError(
            f"Launch file {launch_file} not found in package {package}"
        )

    service = LaunchService()
    context = service.context

    for arg in launch_args:
        if ":=" in arg:
            k, _, v = arg.partition(":=")
            context.launch_configurations[k] = v

    source = AnyLaunchDescriptionSource(launch_path)
    ld = source.get_launch_description(context)

    return inspect_launch_description(ld, context)


def main() -> int:
    if len(sys.argv) < 3:
        print(
            "Usage: python3 -m fish.launch_inspect <package> <launch_file> [arg:=val ...]",
            file=sys.stderr,
        )
        return 2

    package = sys.argv[1]
    launch_file = sys.argv[2]
    launch_args = sys.argv[3:]

    # Launch framework sometimes writes log messages (e.g. validation errors)
    # to stdout via Python's logging. Redirect stdout to stderr for the
    # duration of inspection so the JSON output remains clean.
    import io
    original_stdout = sys.stdout
    sys.stdout = sys.stderr  # launch framework logs go to stderr

    try:
        result = inspect_launch(package, launch_file, launch_args)
    except Exception as e:
        sys.stdout = original_stdout
        print(f"[FISH] launch_inspect error: {e}", file=sys.stderr)
        traceback.print_exc(file=sys.stderr)
        print("{}")  # graceful fallback
        return 0

    # Restore real stdout and emit JSON
    sys.stdout = original_stdout
    json.dump(result, sys.stdout, indent=2, default=str)
    print()
    return 0


if __name__ == "__main__":
    sys.exit(main())
